import type { Signal } from './signal';

export class Module<ParamName extends string> {
  static make<const ParamName extends string, const InputParamName extends ParamName | null>(
    defaultParamValues: Record<ParamName, () => Signal>,
    makeSignal: (params: Record<ParamName, Signal>) => Signal,
    description: string | null = null
  ): Module<ParamName> {
    return new Module<ParamName>(defaultParamValues, makeSignal, description);
  }

  private constructor(
    readonly defaultParamValues: Record<ParamName, () => Signal>,
    private readonly makeSignal: <T extends ParamName>(params: Record<T, Signal>) => Signal,
    readonly description: string | null = null
  ) {}

  new(paramValues: Partial<Record<ParamName, Signal>>): Signal {
    const allParamValues = { ...paramValues } as {};
    for (const [name, makeValue] of Object.entries(this.defaultParamValues)) {
      if (!paramValues.hasOwnProperty(name)) {
        allParamValues[name] = (makeValue as () => Signal)();
      }
    }
    return this.makeSignal(allParamValues);
  }

  paramNames(): ParamName[] {
    return Object.keys(this.defaultParamValues) as ParamName[];
  }
}

export class InlinedModule<ParamName extends string> {
  static make<const ParamName extends string, const InputParamName extends ParamName | null>(
    defaultParamValues: Record<ParamName, string>,
    codegen: (params: Record<ParamName, string>) => string,
    description: string | null = null
  ): InlinedModule<ParamName> {
    return new InlinedModule<ParamName>(defaultParamValues, codegen);
  }

  private constructor(
    readonly defaultParamValues: Record<ParamName, string>,
    private readonly codegenFn: <T extends ParamName>(params: Record<T, string>) => string,
    readonly description: string | null = null
  ) {}

  codegen(paramValues: Partial<Record<ParamName, string>>): string {
    return this.codegenFn({ ...this.defaultParamValues, ...paramValues });
  }

  paramNames(): ParamName[] {
    return Object.keys(this.defaultParamValues) as ParamName[];
  }
}
