import { Signal } from './signal';
import { compile } from './compiler';
import {
  MessageFromSynthWorklet,
  MessageToSynthWorklet,
  Pattern,
  PatternName,
  PatternStepTiming,
  SequencerState,
} from './types';
import { Synth } from './synth';
import { noteOff, noteOn } from './midi-message-constructors';
import { P_TEMPO, SAMPLE_RATE_RECIP } from './constants';
import { clamp } from './helpers';
import { Module } from './module';
import { updateAiModules } from './ai-modules';
import { Metronome } from './metronome';

export class Msynth extends AudioWorkletProcessor implements AudioWorkletProcessorImpl {
  voiceParams: Float32Array<any>[] = [];
  voiceSamplerStates: Float32Array<any>[] = [];
  voices: Synth[] = [];
  samples = new Float32Array<any>(0);
  numSamples = 0;
  recordingSamples = false;
  readonly sequencer = new Sequencer(this);
  aiModules: Record<string, Module<any>> = {};

  constructor() {
    super();
    this.port.onmessage = (msg: MessageEvent<MessageToSynthWorklet>) => this.onMessage(msg.data);
  }

  sendMessage(msg: MessageFromSynthWorklet, transferObjects: Transferable[] = []) {
    this.port.postMessage(msg, transferObjects);
  }

  onMessage(msg: MessageToSynthWorklet) {
    switch (msg.command) {
      case 'init': {
        this.voiceParams = msg.voiceParams.map(buffer => new Float32Array<any>(buffer));
        this.voiceSamplerStates = msg.voiceSamplerStates.map(
          buffer => new Float32Array<any>(buffer)
        );
        this.samples = new Float32Array<any>(msg.samples);
        break;
      }
      case 'load ai modules': {
        this.aiModules = updateAiModules(msg.modules);
        break;
      }
      case 'load patch': {
        try {
          const { makeSignals } = compile(msg.code, this.aiModules);
          const newVoices: Synth[] = [];
          for (let channel = 0; channel < (msg.mono ? 1 : this.voiceParams.length); channel++) {
            const allSignals: Signal[] = [];
            const outs = Signal.doCollectingNewInstances(makeSignals, allSignals);
            newVoices.push(
              new Synth(
                this,
                channel,
                outs,
                allSignals,
                this.voiceParams[channel],
                this.voiceSamplerStates[channel]
              )
            );
          }
          this.voices = newVoices;
        } catch (e: any) {
          this.sendMessage({
            event: 'log',
            message: `error loading patch: ${e.message}`,
          });
          console.error(e);
        }
        break;
      }
      case 'process midi message': {
        for (let voice of this.voices) {
          voice.processMidiMessage(msg.data);
        }
        break;
      }
      case 'sampler: set num samples': {
        this.numSamples = msg.value;
        break;
      }
      case 'sampler: start recording': {
        this.setNumSamples(0);
        this.recordingSamples = true;
        break;
      }
      case 'sampler: stop recording': {
        this.recordingSamples = false;
        break;
      }
      case 'sequencer: set curr pattern': {
        this.sequencer.setCurrPattern(msg.pattern);
        break;
      }
      case 'sequencer: set next pattern': {
        this.sequencer.setNextPattern(msg.pattern);
        break;
      }
      case 'sequencer: set pattern steps': {
        this.sequencer.setPatternSteps(msg.pattern, msg.steps);
        break;
      }
      case 'sequencer: set trigger period': {
        this.sequencer.setTriggerPeriod(msg.value);
        break;
      }
      case 'sequencer: set note duration': {
        this.sequencer.setNoteDuration(msg.value);
        break;
      }
      case 'sequencer: set swing': {
        this.sequencer.setSwing(msg.value);
        break;
      }
      case 'sequencer: start': {
        this.sequencer.start();
        break;
      }
      case 'sequencer: stop': {
        this.sequencer.stop();
        break;
      }
      case 'sequencer rhythm: start recording': {
        this.sequencer.rhythmStartRecording();
        break;
      }
      case 'sequencer rhythm: cancel recording': {
        this.sequencer.rhythmRecordingCancel();
        break;
      }
      case 'sequencer rhythm: finger down': {
        this.sequencer.rhythmRecordingFingerDown();
        break;
      }
      case 'sequencer rhythm: finger up': {
        this.sequencer.rhythmRecordingFingerUp();
        break;
      }
      default: {
        console.error('unsupported message', msg);
        throw new Error('unsupported message!');
      }
    }
  }

  private lastAudioErrorAt = 0;
  private static readonly AUDIO_ERROR_COOLDOWN_SECONDS = 2;

  process(inputs: Float32Array[][], [output]: Float32Array[][], parameters: any) {
    const numFrames = output[0].length;
    try {
      if (this.recordingSamples) {
        this.recordSamples(inputs, numFrames);
      }
      this.sequencer.run(numFrames);
      for (let frameIdx = 0; frameIdx < numFrames; frameIdx++) {
        this.sequencer.mixMetronomeInto(output, frameIdx);
        for (const voice of this.voices) {
          voice.processFrame(inputs, output, frameIdx);
        }
      }
    } catch (e: any) {
      const now = currentTime;
      if (now - this.lastAudioErrorAt >= Msynth.AUDIO_ERROR_COOLDOWN_SECONDS) {
        this.lastAudioErrorAt = now;
        this.sendMessage({
          event: 'log',
          message: `Audio: exception in synth (${e?.message ?? e}). Output muted for this block.`,
        });
      }
      for (let ch = 0; ch < output.length; ch++) {
        output[ch].fill(0);
      }
    }
    return true;
  }

  recordSamples(inputs: Float32Array[][], numFrames: number) {
    let n = this.numSamples;
    for (let frameIdx = 0; frameIdx < numFrames; frameIdx++) {
      if (n >= this.samples.length) {
        break;
      }
      const sample = inputs[0]?.[0]?.[frameIdx] ?? 0;
      this.samples[n++] = sample;
    }
    this.setNumSamples(n);
  }

  setNumSamples(value: number) {
    this.numSamples = value;
    this.sendMessage({ event: 'sampler: num samples', value });
  }
}

class Sequencer {
  private readonly metronome = new Metronome();
  state: SequencerState = {
    patternA: { notes: [] },
    patternB: { notes: [] },
    currPattern: 'A',
    currStep: -1,
    nextPattern: 'A',
    triggerPeriod: 1 / 8,
    noteDuration: 0.5,
    swing: 0.5,
    playing: false,
    recordingRhythmStepIdx: null,
  };
  /** Elapsed time since the current step's note-on, in units of one 4/4 measure (same as rhythm duration/restAfter). */
  private elapsedMeasuresSinceStepStart = Infinity;

  constructor(public synth: Msynth) {}

  setCurrPattern(pattern: PatternName) {
    this.stop(false); // don't send new state yet
    this.state.currPattern = this.state.nextPattern = pattern;
    this.sendNewState();
  }

  setNextPattern(pattern: PatternName | '●') {
    this.state.nextPattern = pattern;
    this.sendNewState();
  }

  setPatternSteps(pattern: PatternName, steps: Pattern) {
    this.stop(false); // don't send new state yet
    if (pattern === 'A') {
      this.state.patternA = steps;
    } else {
      this.state.patternB = steps;
    }
    this.sendNewState();
  }

  setTriggerPeriod(value: number) {
    this.state.triggerPeriod = Math.max(0.01, value);
    this.sendNewState();
  }

  setNoteDuration(value: number) {
    this.state.noteDuration = clamp(value, 0.01, 0.99);
    this.sendNewState();
  }

  setSwing(value: number) {
    this.state.swing = clamp(value, 0.01, 0.99);
    this.sendNewState();
  }

  start() {
    this.state.recordingRhythmStepIdx = null;
    this.state.playing = true;
    this.state.currStep = 0;
    this.elapsedMeasuresSinceStepStart = 0;
    this.playStep(this.state.currStep, 'noteOn');
    this.sendNewState();
  }

  stop(sendNewState: boolean = true) {
    this.playStep(this.state.currStep, 'noteOff');
    this.state.playing = false;
    this.state.currStep = -1;
    if (sendNewState) {
      this.sendNewState();
    }
  }

  /** Seconds since rhythm recording started; drives metronome clicks on the seq div grid. */
  private rhythmMetronomeTimeSec = 0;
  private fingerDownTimestamp = 0;
  private fingerUpTimestamp = 0;
  private recordedRhythm: PatternStepTiming[] = [];

  rhythmStartRecording() {
    if (this.currPattern.notes.length === 0) {
      this.synth.sendMessage({ event: 'log', message: 'cannot record rhythm: pattern is empty!' });
      return;
    }

    this.stop(false);
    this.state.recordingRhythmStepIdx = 0;
    this.recordedRhythm = [];
    this.rhythmMetronomeTimeSec = 0;
    this.metronome.click(true);
    this.sendNewState();
  }

  rhythmRecordingCancel() {
    this.state.recordingRhythmStepIdx = null;
    this.currPattern.rhythm = null;
    this.rhythmMetronomeTimeSec = 0;
    this.sendNewState();
  }

  rhythmRecordingFingerDown() {
    this.fingerDownTimestamp = currentTime;

    if (this.recordedRhythm.length > 0) {
      // update the previous step's rest after
      this.recordedRhythm.at(-1)!.restAfter =
        ((this.fingerDownTimestamp - this.fingerUpTimestamp) * this.tempo) / 4 / 60;
    }

    const pattern = this.currPattern;
    if (this.recordedRhythm.length === pattern.notes.length) {
      this.rhythmRecordingEnd();
    } else {
      const stepIdx = this.recordedRhythm.length;
      // add a new step to the recorded rhythm
      this.recordedRhythm.push({ duration: 0, restAfter: 0 });
      this.playStep(stepIdx, 'noteOn');
      this.sendNewState();
    }
  }

  rhythmRecordingFingerUp() {
    this.fingerUpTimestamp = currentTime;
    const step = this.recordedRhythm.at(-1)!;
    if (!step) {
      // haven't had a finger down for the first step yet
      // (this finger up is from the gesture that starts recording the rhythm)
    } else {
      const stepIdx = this.recordedRhythm.length - 1;
      step.duration = ((this.fingerUpTimestamp - this.fingerDownTimestamp) * this.tempo) / 4 / 60;
      this.playStep(stepIdx, 'noteOff');
      this.state.recordingRhythmStepIdx++;
    }
  }

  private rhythmRecordingEnd() {
    // done! so quantize the pattern's length to a time division...
    const totalTime = this.recordedRhythm.reduce(
      (acc, step) => acc + step.duration + step.restAfter,
      0
    );
    const roundedTime = Math.max(
      this.state.triggerPeriod,
      Math.round(totalTime / this.state.triggerPeriod) * this.state.triggerPeriod
    );
    const timeFactor = roundedTime / totalTime;
    this.recordedRhythm.forEach(step => {
      step.duration *= timeFactor;
      step.restAfter *= timeFactor;
    });

    // add the recorded rhythm to the pattern...
    this.currPattern.rhythm = this.recordedRhythm;

    // then clean up and start playing
    this.state.recordingRhythmStepIdx = null;
    this.rhythmMetronomeTimeSec = 0;
    this.start(); // sends new state
  }

  mixMetronomeInto(output: Float32Array[], frameIdx: number) {
    if (this.state.recordingRhythmStepIdx === null) {
      return;
    }

    const tempo = this.synth.voices[0]?.params[P_TEMPO] ?? 120;
    const secondsPerMeasure = (4 * 60) / tempo;
    const secondsPerClick = this.state.triggerPeriod * secondsPerMeasure;
    if (secondsPerClick <= 0) {
      return;
    }

    const t0 = this.rhythmMetronomeTimeSec;
    this.rhythmMetronomeTimeSec += SAMPLE_RATE_RECIP;
    const t1 = this.rhythmMetronomeTimeSec;
    const c0 = Math.floor(t0 / secondsPerClick);
    const c1 = Math.floor(t1 / secondsPerClick);
    if (c1 > c0) {
      for (let c = c0 + 1; c <= c1; c++) {
        this.metronome.click(c % 4 === 0);
      }
    }
    this.metronome.mixInto(output, frameIdx);
  }

  private sendNewState() {
    this.synth.sendMessage({ event: 'sequencer: state', state: this.state });
  }

  private notesAreOn = false;
  private channelsUsed: number[] = [];

  private get currPattern() {
    return this.state.currPattern === 'A' ? this.state.patternA : this.state.patternB;
  }

  /** Grid step length in measure units (triggerPeriod is a fraction of a 4/4 measure). */
  private get gridStepDurationInMeasures() {
    const swingAdjustment =
      this.state.currStep % 2 === 1 ? 2 * this.state.swing : 2 * (1 - this.state.swing);
    return this.state.triggerPeriod * swingAdjustment;
  }

  run(numFrames: number) {
    if (!this.state.playing || this.currPattern.notes.length === 0) {
      return;
    }

    const secondsElapsed = numFrames * SAMPLE_RATE_RECIP;
    const secondsPerQuarterNote = 60 / this.tempo;
    const secondsPerMeasure = 4 * secondsPerQuarterNote;
    const elapsedMeasuresThisBlock = secondsElapsed / secondsPerMeasure;

    let totalTimeForThisStep: number;
    let durationForThisStep: number;
    if (this.currPattern.rhythm) {
      const { duration, restAfter } = this.currPattern.rhythm[this.state.currStep];
      totalTimeForThisStep = duration + restAfter;
      durationForThisStep = duration;
    } else {
      totalTimeForThisStep = this.gridStepDurationInMeasures;
      durationForThisStep = totalTimeForThisStep * this.state.noteDuration;
    }

    if (this.notesAreOn && this.elapsedMeasuresSinceStepStart >= durationForThisStep) {
      this.playStep(this.state.currStep, 'noteOff');
    }

    if (this.elapsedMeasuresSinceStepStart >= totalTimeForThisStep) {
      this.state.currStep = (this.state.currStep + 1) % this.currPattern.notes.length;
      if (this.state.currStep === 0 && this.state.nextPattern !== this.state.currPattern) {
        if (this.state.nextPattern === '●') {
          this.state.playing = false;
          this.state.currStep = -1;
        } else {
          this.state.currPattern = this.state.nextPattern;
        }
        this.sendNewState();
      }
      if (this.state.currStep >= 0) {
        this.playStep(this.state.currStep, 'noteOn');
      }
      this.elapsedMeasuresSinceStepStart -= totalTimeForThisStep;
    }

    this.elapsedMeasuresSinceStepStart += elapsedMeasuresThisBlock;
  }

  private get tempo() {
    return this.synth.voices[0]!.params[P_TEMPO];
  }

  private playStep(stepIdx: number, action: 'noteOn' | 'noteOff') {
    const step = this.currPattern.notes[stepIdx];
    if (!step) {
      return;
    }

    if (action === 'noteOn') {
      this.channelsUsed = [];
      this.notesAreOn = true;
    } else {
      this.notesAreOn = false;
    }

    this.synth.sendMessage({
      event: 'sequencer: step',
      pattern: this.state.currPattern,
      index: this.state.currStep,
      action,
    });

    step.forEach((note, idx) => {
      let ch: number;
      if (action === 'noteOn') {
        ch = this.nextVoiceIdx();
        this.channelsUsed.push(ch);
      } else {
        ch = this.channelsUsed[idx];
      }
      this.synth.voices[ch]?.processMidiMessage(
        (action === 'noteOn' ? noteOn : noteOff)(ch, note, 127)
      );
    });
  }

  // Note: this only works well b/c the user is not allowed to play notes while the sequencer is playing!
  private lastVoiceIdx = -1;
  private nextVoiceIdx() {
    const idx = (this.lastVoiceIdx + 1) % this.synth.voices.length;
    this.lastVoiceIdx = idx;
    return idx;
  }
}

registerProcessor('msynth', Msynth);
